from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build a map of all subjects to their triples
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main building (subject with most triples or first one)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))
    main_triples = subject_triples[main_subject]

    # Separate triples by category for better sentence flow
    location_triples = [t for t in main_triples if t.predicate in ["location", "country", "state", "region", "address", "isPartOf"]]
    design_triples = [t for t in main_triples if t.predicate in ["architect", "architecturalStyle", "developer", "owner"]]
    construction_triples = [t for t in main_triples if t.predicate in ["buildingStartDate", "completionDate", "yearOfConstruction", "inaugurationDate", "height", "floorCount", "cost", "floorArea"]]
    other_triples = [t for t in main_triples if t not in location_triples + design_triples + construction_triples]

    # Build location hierarchy (handle isPartOf relationships properly)
    location_parts = []
    if location_triples:
        # Find the most specific location first
        location_triple = next((t for t in location_triples if t.predicate == "location"), None)
        if location_triple:
            location_parts.append(f"located at {location_triple.object}")

        # Handle country, state, region separately
        country_triple = next((t for t in location_triples if t.predicate == "country"), None)
        state_triple = next((t for t in location_triples if t.predicate == "state"), None)
        region_triple = next((t for t in location_triples if t.predicate == "region"), None)
        address_triple = next((t for t in location_triples if t.predicate == "address"), None)

        # Handle isPartOf relationships hierarchically
        is_part_of_triples = [t for t in location_triples if t.predicate == "isPartOf"]

        if state_triple:
            location_parts.append(f"in {state_triple.object}")
        if country_triple:
            location_parts.append(f"in {country_triple.object}")
        if region_triple:
            location_parts.append(f"in the {region_triple.object} region")
        if address_triple:
            location_parts.append(f"at {address_triple.object}")

        # Add isPartOf info if not already covered
        for t in is_part_of_triples:
            if not any(t.object in part for part in location_parts):
                location_parts.append(f"part of {t.object}")

    # Build design information
    design_parts = []
    architect_triple = next((t for t in design_triples if t.predicate == "architect"), None)
    style_triple = next((t for t in design_triples if t.predicate == "architecturalStyle"), None)
    owner_triple = next((t for t in design_triples if t.predicate == "owner"), None)
    developer_triple = next((t for t in design_triples if t.predicate == "developer"), None)

    if architect_triple:
        design_parts.append(f"designed by {architect_triple.object}")
    if style_triple:
        design_parts.append(f"featuring {style_triple.object}")
    if owner_triple:
        design_parts.append(f"owned by {owner_triple.object}")
    if developer_triple:
        design_parts.append(f"developed by {developer_triple.object}")

    # Build construction information
    construction_parts = []
    for t in construction_triples:
        if t.predicate == "height":
            construction_parts.append(f"standing {t.object} tall")
        elif t.predicate == "floorCount":
            construction_parts.append(f"with {t.object} floors")
        elif t.predicate == "cost":
            construction_parts.append(f"at a cost of {t.object}")
        elif t.predicate == "floorArea":
            construction_parts.append(f"covering {t.object}")
        elif t.predicate in ["buildingStartDate", "yearOfConstruction"]:
            construction_parts.append(f"built in {t.object}")
        elif t.predicate == "completionDate":
            construction_parts.append(f"completed in {t.object}")
        elif t.predicate == "inaugurationDate":
            construction_parts.append(f"inaugurated on {t.object}")

    # Build the sentence with proper structure
    sentence_parts = []

    # Start with subject
    type_triple = next((t for t in main_triples if t.predicate == "buildingType"), None)
    if type_triple:
        sentence_parts.append(f"{main_subject} is a {type_triple.object}")
    else:
        sentence_parts.append(main_subject)

    # Add design info
    if design_parts:
        sentence_parts.append(f", {', '.join(design_parts)}")

    # Add construction info
    if construction_parts:
        sentence_parts.append(f", {', '.join(construction_parts)}")

    # Add location info
    if location_parts:
        sentence_parts.append(f", {', '.join(location_parts)}")

    # Add other info
    if other_triples:
        other_parts = []
        for t in other_triples:
            other_parts.append(f"{t.predicate.replace('_', ' ')} {t.object}")
        if other_parts:
            sentence_parts.append(f", {', '.join(other_parts)}")

    # Join all parts into one sentence
    sentence = ''.join(sentence_parts)

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END
